import React from 'react';
import { Brain } from 'lucide-react';
import { useTheme } from '../contexts/ThemeContext';

const BrainLogo = ({ size = 'w-7 h-7', className = '' }) => {
  const { isDarkMode } = useTheme();
  
  if (isDarkMode) {
    // Use the original lucide Brain icon for dark mode
    return (
      <Brain 
        className={`${size} ${className}`} 
        style={{ color: "#D4AF37" }} 
        strokeWidth={1.5} 
      />
    );
  }
  
  // Use custom green brain SVG for light mode
  return (
    <svg 
      className={`${size} ${className}`}
      viewBox="0 0 24 24" 
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
    >
      <g stroke="#87A96B" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round">
        {/* Left brain hemisphere */}
        <path d="M9.5 3C6.5 3 4 5.5 4 8.5c0 1.5 0.5 3 1.5 4C4.5 13.5 4 15 4 16.5c0 2.5 2 4.5 4.5 4.5h2.5V8.5C11 5.5 10.5 3 9.5 3z"/>
        
        {/* Right brain hemisphere */}
        <path d="M14.5 3c3 0 5.5 2.5 5.5 5.5c0 1.5-0.5 3-1.5 4c1 1 1.5 2.5 1.5 4c0 2.5-2 4.5-4.5 4.5H13V8.5C13 5.5 13.5 3 14.5 3z"/>
        
        {/* Brain stem */}
        <path d="M11 21v1.5c0 0.5 0.5 1 1 1h0c0.5 0 1-0.5 1-1V21"/>
        
        {/* Brain folds/details */}
        <path d="M7 9c1 0 1.5 1 1.5 2"/>
        <path d="M16.5 9c-1 0-1.5 1-1.5 2"/>
        <path d="M6.5 13.5c1-0.5 2-0.5 3 0"/>
        <path d="M17.5 13.5c-1-0.5-2-0.5-3 0"/>
        
        {/* Additional brain texture */}
        <path d="M8.5 15.5c0.5-0.5 1.5-0.5 2 0"/>
        <path d="M15.5 15.5c-0.5-0.5-1.5-0.5-2 0"/>
      </g>
    </svg>
  );
};

export default BrainLogo;
